1	interface QuoteItem {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteInput {
9	  customer: { yearsWithMHPCO: number };
10	  items: QuoteItem[];
11	  contractIndex?: number;
12	}
13	
14	const PROCESSING_FEE = 5;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const BLOCK_SIZE = 3;
26	const BLOCK_PREMIUM = 60;
27	
28	const CURSE_SURCHARGE_RATE = 0.5;
29	
30	function countByType(items: QuoteItem[]): Map<string, number> {
31	  const counts = new Map<string, number>();
32	  for (const item of items) {
33	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
34	  }
35	  return counts;
36	}
37	
38	function priceGroup(type: string, count: number): number {
39	  return count === BLOCK_SIZE ? BLOCK_PREMIUM : BASE_PREMIUMS[type] * count;
40	}
41	
42	function curseSurchargeFor(items: QuoteItem[]): number {
43	  let surcharge = 0;
44	  for (const item of items) {
45	    if (item.cursed) {
46	      surcharge += BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE;
47	    }
48	  }
49	  return surcharge;
50	}
51	
52	function basePremiumFor(items: QuoteItem[]): number {
53	  const countsByType = countByType(items);
54	
55	  let basePremium = 0;
56	  for (const [type, count] of countsByType) {
57	    basePremium += priceGroup(type, count);
58	  }
59	  return basePremium + curseSurchargeFor(items);
60	}
61	
62	export function quote(input: QuoteInput): number {
63	  return basePremiumFor(input.items) + PROCESSING_FEE;
64	}
65	
66	export function claim(input: unknown): number {
67	  return undefined as unknown as number;
68	}
